import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';

test.describe('Login Page — easy-login', () => {
  test.afterEach(async ({ page }, testInfo) => {
    if (testInfo.status !== testInfo.expectedStatus) {
      const name = testInfo.title.replace(/[^a-z0-9]/gi, '-');
      await page.screenshot({ path: `evidence/${name}-FAIL.png`, fullPage: true });
    }
  });

  test.describe.configure({ mode: 'serial' });

  test('LOGIN-01 — Successful login with valid credentials', async ({ page }) => {
    // Step 1: Navigate to the login page
    await page.goto(`${BASE_URL}/login`);

    // Step 2: Enter registered email
    await page.getByLabel('Email address').fill('user@example.com');

    // Step 3: Enter correct password
    await page.getByLabel('Password').fill('correct-password');

    // Step 4: Submit the form
    await page.getByRole('button', { name: 'Sign in' }).click();

    // [VERIFY] Confirm redirect destination matches product specification
    await expect(page).not.toHaveURL(`${BASE_URL}/login`);
    await page.screenshot({ path: 'evidence/LOGIN-01-success.png' });
  });

  test('LOGIN-04 — Empty form submission shows inline errors', async ({ page }) => {
    // Step 1: Navigate to the login page
    await page.goto(`${BASE_URL}/login`);

    // Step 2: Submit without entering data
    await page.getByRole('button', { name: 'Sign in' }).click();

    // [VERIFY] Confirm aria-describedby linkage for email error
    const emailError = page.locator('#email-error');
    await emailError.waitFor({ state: 'visible' });
    // [VERIFY] Confirm aria-describedby linkage for password error
    const passwordError = page.locator('#password-error');
    await passwordError.waitFor({ state: 'visible' });

    await page.screenshot({ path: 'evidence/LOGIN-04-empty-form.png' });
  });

  test('LOGIN-06 — Keyboard navigation through form in DOM order', async ({ page }) => {
    // Step 1: Navigate to the login page
    await page.goto(`${BASE_URL}/login`);

    // Step 2: Tab through form fields
    await page.keyboard.press('Tab');
    // [VERIFY] Confirm email input receives focus first
    await expect(page.getByLabel('Email address')).toBeFocused();

    await page.keyboard.press('Tab');
    // [VERIFY] Confirm password input receives focus second
    await expect(page.getByLabel('Password')).toBeFocused();

    await page.keyboard.press('Tab');
    // [VERIFY] Confirm Sign in button receives focus third
    await expect(page.getByRole('button', { name: 'Sign in' })).toBeFocused();

    await page.screenshot({ path: 'evidence/LOGIN-06-keyboard-nav.png' });
  });
});
